module top_module(
	A,		
	B,		
	C,		
	D,		
	obf_Ctrl,	
	S		
	);parameter N = 16;
	input wire [N - 1: 0] A, B, C, D;
	output wire [N - 1: 0] S;
	input wire [1:0] obf_Ctrl;

	assign S = (obf_Ctrl == 2'b00) ? A :
				  ((obf_Ctrl == 2'b01) ? B :
				  ((obf_Ctrl == 2'b10) ? C : D
				  ));

endmodule
